		'madb_howr1' => Request::lookup('madb_howr1', ''),
		'madb_hows1' => Request::lookup('madb_hows1', ''),
		'madb_howq1' => Request::lookup('madb_howq1', ''),
		'madb_howt1' => Request::lookup('madb_howt1', ''),
		'madb_why2' => Request::lookup('madb_why1'),
		'madb_why3' => Request::lookup('madb_why1'),
		'madb_where2' => Request::lookup('madb_where1'),
		'madb_where3' => Request::lookup('madb_where1'),
		'madb_which2' => Request::lookup('madb_which1'),
		'madb_which3' => Request::lookup('madb_which1'),
		'madb_when2' => Request::lookup('madb_when1'),
		'madb_when3' => Request::lookup('madb_when1'),
		'madb_who2' => Request::lookup('madb_who1'),
		'madb_who3' => Request::lookup('madb_who1'),
		'madb_what2' => Request::lookup('madb_what1'),
		'madb_what3' => Request::lookup('madb_what1'),
		'madb_howr2' => Request::lookup('madb_howr1'),
		'madb_howr3' => Request::lookup('madb_howr1'),
		'madb_hows2' => Request::lookup('madb_hows1'),
		'madb_hows3' => Request::lookup('madb_hows1'),
		'madb_howq2' => Request::lookup('madb_howq1'),
		'madb_howq3' => Request::lookup('madb_howq1'),
		'madb_howt2' => Request::lookup('madb_howt1'),
		'madb_howt3' => Request::lookup('madb_howt1'),
		'madb_premises_id' => Request::lookup('madb_premises_id', ''),
		'madb_updated' => parseCode('<%%editingTimestamp%%>', false, true),
	];

	// get existing values
	$old_data = getRecord('madb', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: madb_before_update
	if(function_exists('madb_before_update')) {
		$args = ['old_data' => $old_data];
		if(!madb_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'madb',
		backtick_keys_once($set),
		['`madb_id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="madb_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('madb', $data['selectedID'], calculated_fields()['madb']);

	// hook: madb_after_update
	if(function_exists('madb_after_update')) {
		if($row = getRecord('madb', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['madb_id'];
		$args = ['old_data' => $old_data];
		if(!madb_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('madb', $selected_id);
}

